INSERT INTO mdm_schema.other_cost_item (other_cost_item_name, other_cost_item_desc, other_cost_item_handle, created_by, updated_by) VALUES
('Equipment Rental', 'Hiring cost for construction machinery like cranes, excavators, and batching plants.', 'equipment-rental', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('Fuel & Lubricants', 'Cost of diesel, petrol, grease, and lubricants for site machinery and generators.', 'fuel-lubricants', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('Equipment Maintenance', 'Expenses for servicing and repairs of construction equipment.', 'equipment-maintenance', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('Operator Charges', 'Payments to operators for handling machinery like cranes, batching plants, etc.', 'operator-charges', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('Small Tools Purchase', 'Procurement of hand tools like grinders, trowels, drills, etc.', 'small-tools-purchase', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('Consumables', 'Items like drill bits, welding rods, cutting blades, tapes, etc., consumed in use.', 'consumables', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('Tool Maintenance', 'Cost of repairing or replacing damaged/worn-out tools.', 'tool-maintenance', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('Site Office Setup', 'Installation of site cabins, furniture, IT equipment, and other setup expenses.', 'site-office-setup', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('Site Utilities', 'Electricity, water, internet, and drainage facilities set up for the site.', 'site-utilities', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('Site Toilets', 'Installation and maintenance of sanitation facilities for workers and staff.', 'site-toilets', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('Fencing & Barricading', 'Temporary fencing and barricades for security and demarcation.', 'fencing-barricading', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('Access Road Creation', 'Creating temporary roads or pathways for material and equipment movement.', 'access-road-creation', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('PPE (Safety Gear)', 'Purchase of helmets, gloves, jackets, boots, harnesses, etc.', 'ppe-safety-gear', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('Safety Signage', 'Signboards, warning signs, and directional signage on site.', 'safety-signage', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('First Aid & Medical', 'Basic emergency kits and provision for medical attention.', 'first-aid-medical', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('Fire Safety Equipment', 'Fire extinguishers, sand buckets, and smoke detection systems.', 'fire-safety-equipment', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('Safety Trainings', 'Toolbox talks, safety inductions, and mock drill arrangements.', 'safety-trainings', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('Third-Party Testing', 'Testing of concrete, soil, steel, etc. by certified labs.', 'third-party-testing', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('Survey Equipment & Support', 'Use and rental of total stations, levels, and surveyor charges.', 'survey-equipment-support', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('Statutory Approvals', 'Costs for permits and regulatory clearances.', 'statutory-approvals', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('Insurance', 'Project-related insurances including workmen, machinery, and public liability.', 'insurance', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('Daily Reporting', 'Manual or software-based documentation of site progress.', 'daily-reporting', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('Loading/Unloading', 'Cost of manual or mechanical loading/unloading of materials.', 'loading-unloading', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('Transportation', 'Internal and external movement of materials, debris, and equipment.', 'transportation', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('Watch & Ward', 'Site security including guards, access control, and CCTV.', 'watch-ward', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('Cleaning Staff', 'Hiring personnel for daily cleaning of site areas.', 'cleaning-staff', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('Waste Disposal', 'Collection and disposal of construction debris and waste.', 'waste-disposal', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('Septic Maintenance', 'Cleaning and maintenance of septic tanks for mobile toilets.', 'septic-maintenance', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('Communication', 'Mobile, internet, and walkie-talkie costs for site coordination.', 'communication', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('Stationery & Supplies', 'Registers, papers, markers, forms used at site.', 'stationery-supplies', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('Refreshments', 'Tea, coffee, and drinking water for site staff and labor.', 'refreshments', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001'),
('Miscellaneous Expenses', 'Daily petty cash spends and minor unplanned purchases.', 'miscellaneous-expenses', '00000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001');
